var e=[{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`먼 곳에서 폭격소리가 들려왔다.`,JPN:`遠方から爆撃音が聞こえてきた。`,ENG:`I heard the sound of bombing in the distance.`,TWN:`聽到從遠處傳來的轟炸聲。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`군인들이 우리를 구하러 와 주는 소리이길 바랐지만, 그런 일은 일어나지 않았다.`,JPN:`軍人が私たちを助けに来た音だと願ったが、そんなことは起きなかった。`,ENG:`I hoped it was the sound of the government soldiers coming to save us. It wasn't. It never was.`,TWN:`雖然心裡默默期待是要來救我們的，但事與願違。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`철문이 열리며 반군 어른은 오늘은 평소보다 많은 다섯 명을 불렀다.`,JPN:`鉄の扉が開かれ、反乱軍の大人がいつもよりも多く5人を呼び出した。`,ENG:`When the metal door opened, the adult rebels called five of us, which was more than usual.`,TWN:`鐵門被打開後，叛軍大人叫來5個孩子，這人數比平常還多。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`불려 나간 다섯 아이 중에는, 내게 인형을 준 소녀도 있었다.`,JPN:`呼び出された5人の子どもの中には、私にぬいぐるみをくれた少女もいた。`,ENG:`Among the five was the girl who gave me the doll.`,TWN:`被叫出來的5個孩子中，有一個是送我娃娃的女孩。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`돌아오지 못할 거란 걸 알면서도.`,JPN:`もう帰ってくることはできないと知っていながら。`,ENG:`She knew she'd never come back,`,TWN:`明明知道很可能再也回不來，`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`소녀는 울거나 떨지 않았다.`,JPN:`少女は泣くことも、震えることもなかった。`,ENG:`but she didn't cry or even shake.`,TWN:`她卻一滴眼淚也沒流，靜靜地站著。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:null,text:{KOREA:`먼 곳에서 또 다시 폭격소리가 들렸다.`,JPN:`遠くからまた爆撃音が聞こえた。`,ENG:`Again, I heard the sound of bombing in the distance.`,TWN:`從遠處又再次傳來爆炸聲。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:null,text:{KOREA:`땅이 흔들렸고, 정전이 일어났다.`,JPN:`地面が揺れ、停電が起きた。`,ENG:`The ground shook and the power went out.`,TWN:`爆炸導致地在晃動，甚至還停電。`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`GAEUN_CHILD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`소녀는 어른들의 틈을 해치고 열린 철문 밖으로 뛰쳐나갔다.`,JPN:`少女は大人たちをすり抜けて、開いた鉄の扉の外に飛び出した。`,ENG:`The girl pushed through the grownups, bolting through the opened metal door.`,TWN:`那個女孩趁大人不注意的時候，往鐵門外衝出去。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`가장 먼저 불을 켠 어른이 달아나는 소녀를 보고 소리쳤다.`,JPN:`真っ先に電気をつけた大人が、逃げる少女を見て叫んだ。`,ENG:`The grownup who turned the light back on saw her and shouted.`,TWN:`第一個點著燈的大人，朝著逃跑的女孩大聲喝斥。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:null,text:{KOREA:`하지만 소녀는 멈추지 않았다.`,JPN:`しかし、少女は止まらなかった。`,ENG:`But she didn't stop.`,TWN:`但女孩沒有停下腳步。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:null,text:{KOREA:`나는 쫓아가려는 어른의 다리를 뒤에서 있는 힘껏 붙잡았다.`,JPN:`私は追いかけようとする大人の足を後ろから精一杯掴んだ。`,ENG:`A grownup nearby tried to follow her, and I grabbed his leg from behind.`,TWN:`大人想追上前去，但我從後面拼命抓住他的腳。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:null,text:{KOREA:`멈추지 말고 달려!`,JPN:`立ち止まらずに走って！`,ENG:`Don't stop. Keep running!`,TWN:`別回頭，快跑！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L32_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`헉…… 허억……`,JPN:`はぁ……はぁ……`,ENG:`Huff, huff...`,TWN:`呼……呼呼……`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L34_1`,type:`dialog`,speaker:`CORRUPTED_NPC_LUCID_TAIL`,text:{KOREA:`크르릉?`,JPN:`ガルン？`,ENG:`Grrr?`,TWN:`呼嚕嚕？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};